import{_ as e,c as p,o as l,ag as t}from"./chunks/framework.ELrfyV9R.js";const d=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"ai/2026-03/2026-03-01-agent.md","filePath":"ai/2026-03/2026-03-01-agent.md","lastUpdated":1776945928000}'),i={name:"ai/2026-03/2026-03-01-agent.md"};function o(r,a,n,h,u,c){return l(),p("div",null,a[0]||(a[0]=[t('<h2 id="ai-agent-到底是怎么工作的-一篇讲清楚" tabindex="-1">AI Agent 到底是怎么工作的？一篇讲清楚 <a class="header-anchor" href="#ai-agent-到底是怎么工作的-一篇讲清楚" aria-label="Permalink to &quot;AI Agent 到底是怎么工作的？一篇讲清楚&quot;">​</a></h2><p>在 AI 时代，我们经常听到一个词：<strong>Agent（智能体）</strong>。</p><p>很多人以为它只是“更聪明的聊天机器人”，但其实不一样。<br> 一个真正的 AI Agent，不只是会说话，它还能<strong>思考、行动、复盘，再继续思考</strong>。</p><p>如果用一句话概括：</p><blockquote><p>AI Agent = 会思考的大脑 + 能行动的双手 + 会规划的神经系统 + 稳定运行的身体</p></blockquote><p>下面我们用最通俗的方式讲清楚。</p><hr><h2 id="一、ai-agent-的四个核心部分" tabindex="-1">一、AI Agent 的四个核心部分 <a class="header-anchor" href="#一、ai-agent-的四个核心部分" aria-label="Permalink to &quot;一、AI Agent 的四个核心部分&quot;">​</a></h2><h3 id="_1️⃣-模型-大脑" tabindex="-1">1️⃣ 模型（大脑） <a class="header-anchor" href="#_1️⃣-模型-大脑" aria-label="Permalink to &quot;1️⃣ 模型（大脑）&quot;">​</a></h3><p>这是核心的语言模型（LLM）。</p><p>它负责：</p><ul><li><p>理解问题</p></li><li><p>分析信息</p></li><li><p>做决策</p></li><li><p>生成回答</p></li></ul><p>但注意：<br><strong>模型本身只能“思考”，不能“行动”。</strong></p><hr><h3 id="_2️⃣-工具-双手" tabindex="-1">2️⃣ 工具（双手） <a class="header-anchor" href="#_2️⃣-工具-双手" aria-label="Permalink to &quot;2️⃣ 工具（双手）&quot;">​</a></h3><p>工具让 Agent 能和外部世界互动，比如：</p><ul><li><p>调用 API</p></li><li><p>查询数据库</p></li><li><p>运行代码</p></li><li><p>访问文件</p></li><li><p>调用搜索引擎</p></li></ul><p>如果模型是大脑，工具就是双手。</p><p>没有工具，模型只能“想”；<br> 有了工具，它才能“做”。</p><hr><h3 id="_3️⃣-编排层-神经系统" tabindex="-1">3️⃣ 编排层（神经系统） <a class="header-anchor" href="#_3️⃣-编排层-神经系统" aria-label="Permalink to &quot;3️⃣ 编排层（神经系统）&quot;">​</a></h3><p>这是 Agent 最关键的一层。</p><p>它负责：</p><ul><li><p>规划步骤（Planning）</p></li><li><p>管理记忆（Memory）</p></li><li><p>决定是否调用工具</p></li><li><p>组织每一轮推理</p></li></ul><p>简单说，编排层就是：</p><blockquote><p>决定“下一步该干什么”的控制中心</p></blockquote><hr><h3 id="_4️⃣-部署-身体" tabindex="-1">4️⃣ 部署（身体） <a class="header-anchor" href="#_4️⃣-部署-身体" aria-label="Permalink to &quot;4️⃣ 部署（身体）&quot;">​</a></h3><p>包括：</p><ul><li><p>服务器托管</p></li><li><p>权限控制</p></li><li><p>日志监控</p></li><li><p>安全机制</p></li></ul><p>它保证 Agent 是一个稳定可靠的服务，而不是一次性的实验脚本。</p><hr><h2 id="二、agent-是如何解决问题的" tabindex="-1">二、Agent 是如何解决问题的？ <a class="header-anchor" href="#二、agent-是如何解决问题的" aria-label="Permalink to &quot;二、Agent 是如何解决问题的？&quot;">​</a></h2><p>Agent 不是线性执行流程，而是一个“思考—行动—再思考”的循环。</p><p>它通常这样工作：</p><h3 id="第一步-接收目标" tabindex="-1">第一步：接收目标 <a class="header-anchor" href="#第一步-接收目标" aria-label="Permalink to &quot;第一步：接收目标&quot;">​</a></h3><p>用户提出问题，比如：</p><blockquote><p>“帮我分析今天的销售数据并给出建议。”</p></blockquote><hr><h3 id="第二步-组装上下文" tabindex="-1">第二步：组装上下文 <a class="header-anchor" href="#第二步-组装上下文" aria-label="Permalink to &quot;第二步：组装上下文&quot;">​</a></h3><p>系统会把这些信息打包给模型：</p><ul><li><p>用户的请求</p></li><li><p>历史对话</p></li><li><p>可用工具列表</p></li><li><p>相关数据</p></li><li><p>系统指令</p></li></ul><p>这一步非常关键。</p><hr><h3 id="第三步-模型做判断" tabindex="-1">第三步：模型做判断 <a class="header-anchor" href="#第三步-模型做判断" aria-label="Permalink to &quot;第三步：模型做判断&quot;">​</a></h3><p>模型会思考：</p><ul><li><p>我能直接回答吗？</p></li><li><p>还是需要调用工具？</p></li></ul><p>如果需要数据，它会说：</p><blockquote><p>我要调用数据库查询工具。</p></blockquote><hr><h3 id="第四步-执行工具" tabindex="-1">第四步：执行工具 <a class="header-anchor" href="#第四步-执行工具" aria-label="Permalink to &quot;第四步：执行工具&quot;">​</a></h3><p>编排层拦截这个“工具调用意图”，执行真实代码。</p><p>得到结果后，不直接给用户。</p><p>而是——</p><hr><h3 id="第五步-回填结果-再思考" tabindex="-1">第五步：回填结果，再思考 <a class="header-anchor" href="#第五步-回填结果-再思考" aria-label="Permalink to &quot;第五步：回填结果，再思考&quot;">​</a></h3><p>工具结果会被重新放回上下文。</p><p>模型会再思考一次：</p><blockquote><p>现在我有数据了，我能回答了吗？</p></blockquote><p>如果还不够，它可能继续调用其他工具。</p><hr><h3 id="第六步-输出最终答案" tabindex="-1">第六步：输出最终答案 <a class="header-anchor" href="#第六步-输出最终答案" aria-label="Permalink to &quot;第六步：输出最终答案&quot;">​</a></h3><p>当模型判断信息足够时，才会生成最终回复。</p><p>整个过程像这样：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>思考 → 行动 → 观察 → 再思考 → 再行动 → 输出</span></span></code></pre></div><p>这就是 Agent 的闭环机制。</p><hr><h2 id="三、为什么-agent-比普通-prompt-强" tabindex="-1">三、为什么 Agent 比普通 Prompt 强？ <a class="header-anchor" href="#三、为什么-agent-比普通-prompt-强" aria-label="Permalink to &quot;三、为什么 Agent 比普通 Prompt 强？&quot;">​</a></h2><p>传统方式是：</p><blockquote><p>写一个 Prompt → 得到一个回答 → 结束</p></blockquote><p>而 Agent 是：</p><blockquote><p>管理一个动态上下文环境 → 多轮推理 → 主动调用工具 → 完成目标</p></blockquote><p>这就是从：</p><ul><li>Prompt Engineering（提示词工程）</li></ul><p>进化到：</p><ul><li>Context Engineering（上下文工程）</li></ul><p>你不再只是优化一句话，而是在构建一个“智能系统”。</p><hr><h2 id="四、一个简单类比" tabindex="-1">四、一个简单类比 <a class="header-anchor" href="#四、一个简单类比" aria-label="Permalink to &quot;四、一个简单类比&quot;">​</a></h2><p>开发传统程序像是：</p><blockquote><p>你写好每一步逻辑，机器严格执行。</p></blockquote><p>构建 Agent 更像是：</p><blockquote><p>你设定目标和规则，让它自己规划路径。</p></blockquote><p>你从“写流程的人”变成“导演”。</p><hr><h2 id="五、总结一句话" tabindex="-1">五、总结一句话 <a class="header-anchor" href="#五、总结一句话" aria-label="Permalink to &quot;五、总结一句话&quot;">​</a></h2><p>AI Agent 本质上是一个：</p><blockquote><p>通过管理上下文和工具，在循环中自主完成任务的系统。</p></blockquote><p>当它拥有：</p><ul><li><p>清晰的目标</p></li><li><p>可调用的工具</p></li><li><p>稳定的记忆</p></li><li><p>合理的编排机制</p></li></ul><p>它就不再只是聊天机器人，而是一个能解决问题的“数字员工”。</p><hr><p>如果说大模型是大脑，那么 Agent 是一个完整的人。</p><p>而真正的挑战，不是让模型更聪明，而是：</p><blockquote><p>如何构建一个合理的上下文与行动系统。</p></blockquote>',95)]))}const b=e(i,[["render",o]]);export{d as __pageData,b as default};
